INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "2030/12/17 14:59:59", 0.0, 7, 7001, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "2030/12/17 14:59:59", 0.0, 7, 7002, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "2030/12/17 14:59:59", 0.0, 7, 7003, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", "2030/12/17 14:59:59", 0.0, 10, 10001, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "2030/12/17 14:59:59", 0.0, 10, 10002, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "2030/12/17 14:59:59", 0.0, 10, 10003, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "2030/12/17 14:59:59", 0.0, 10, 10004, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "2030/12/17 14:59:59", 0.0, 12, 12001, 1, 105801, -416.5, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "2030/12/17 14:59:59", 0.0, 13, 13001, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "2030/12/17 14:59:59", 0.0, 13, 13002, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "2030/12/17 14:59:59", 0.0, 13, 13003, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "2030/12/17 14:59:59", 0.0, 13, 13004, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "2030/12/17 14:59:59", 0.0, 14, 14001, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "2030/12/17 14:59:59", 0.0, 14, 14002, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "2030/12/17 14:59:59", 0.0, 14, 14003, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "2030/12/17 14:59:59", 0.0, 14, 14004, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "2030/12/17 14:59:59", 0.0, 15, 15001, 1, 105901, -470.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "2030/12/17 14:59:59", 0.0, 16, 16001, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "2030/12/17 14:59:59", 0.0, 16, 16002, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "2030/12/17 14:59:59", 0.0, 16, 16003, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "2030/12/17 14:59:59", 0.0, 16, 16004, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "2030/12/17 14:59:59", 0.0, 17, 17002, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "2030/12/17 14:59:59", 0.0, 25, 17004, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "2030/12/17 14:59:59", 0.0, 25, 17005, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "2030/12/17 14:59:59", 0.0, 25, 17006, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "2030/12/17 14:59:59", 0.0, 25, 17007, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "2030/12/17 14:59:59", 0.0, 18, 18001, 1, 190801, -363.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 2, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "2030/12/17 14:59:59", 0.0, 18, 18002, 1, 190801, -363.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 3, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "2030/12/17 14:59:59", 0.0, 19, 19001, 1, 190801, -470.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 4, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "2030/12/17 14:59:59", 0.0, 19, 19002, 1, 190801, -470.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 5, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "2030/12/17 14:59:59", 0.0, 20, 20001, 1, 190801, -470.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 6, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "2030/12/17 14:59:59", 0.0, 20, 20002, 1, 190801, -470.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "2030/12/17 14:59:59", 0.0, 21, 21001, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "2030/12/17 14:59:59", 0.0, 21, 21002, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "2030/12/17 14:59:59", 0.0, 21, 21003, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "2030/12/17 14:59:59", 0.0, 21, 21004, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "2030/12/17 14:59:59", 0.0, 22, 22001, 1, 190801, -430.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 2, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "2030/12/17 14:59:59", 0.0, 22, 22002, 1, 190801, -430.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 3, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "2030/12/17 14:59:59", 0.0, 23, 23001, 1, 190801, -430.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 4, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "2030/12/17 14:59:59", 0.0, 23, 23002, 1, 190801, -430.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 1, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "2030/12/17 14:59:59", 8.0, 24, 24001, 1, 109001, -385.0, 2, 4.08, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 2, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "2030/12/17 14:59:59", 8.0, 24, 24002, 1, 109001, -385.0, 2, 5.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 3, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "2030/12/17 14:59:59", 8.0, 24, 24003, 1, 109001, -385.0, 2, 10.11, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 4, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "2030/12/17 14:59:59", 8.0, 24, 24004, 1, 109001, -385.0, 2, 4.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 5, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "2030/12/17 14:59:59", 8.0, 24, 24005, 1, 109001, -385.0, 2, 6.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 6, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "2030/12/17 14:59:59", 0.0, 24, 24006, 1, 109002, 0.0, 1, 0.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 7, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "2030/12/17 14:59:59", 0.0, 24, 24007, 1, 109002, 0.0, 1, 0.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 8, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "2030/12/17 14:59:59", 0.0, 24, 24008, 1, 109002, 0.0, 1, 0.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 9, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "2030/12/17 14:59:59", 0.0, 24, 24009, 1, 109002, 0.0, 1, 0.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 10, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "2030/12/17 14:59:59", 0.0, 24, 24010, 1, 109002, 0.0, 1, 0.0, 10011, "エリコ（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 1, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "2030/12/17 14:59:59", 8.0, 24, 24011, 1, 109101, -385.0, 2, 2.12, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 2, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "2030/12/17 14:59:59", 8.0, 24, 24012, 5, 109101, -385.0, 2, 4.19, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 3, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "2030/12/17 14:59:59", 8.0, 24, 24013, 2, 109101, -385.0, 4, 2.3, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 4, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "2030/12/17 14:59:59", 0.0, 24, 24014, 1, 109102, 0.0, 1, 0.0, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 5, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "2030/12/17 14:59:59", 8.0, 24, 24015, 5, 109101, -385.0, 2, 5.23, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 6, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "2030/12/17 14:59:59", 0.0, 24, 24016, 1, 109102, 0.0, 1, 0.0, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 7, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "2030/12/17 14:59:59", 8.0, 24, 24017, 1, 109101, -385.0, 2, 5.01, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 8, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "2030/12/17 14:59:59", 0.0, 24, 24018, 1, 109102, 0.0, 1, 0.0, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 9, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "2030/12/17 14:59:59", 0.0, 24, 24019, 1, 109102, 0.0, 1, 0.0, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/01/31 12:00:00", 10, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "2030/12/17 14:59:59", 0.0, 24, 24020, 1, 109102, 0.0, 1, 0.0, 10011, "シズル（バレンタイン）");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "2030/12/17 14:59:59", 0.0, 26, 26001, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "2030/12/17 14:59:59", 0.0, 26, 26002, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "2030/12/17 14:59:59", 0.0, 26, 26003, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "2030/12/17 14:59:59", 0.0, 26, 26004, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "2030/12/17 14:59:59", 0.0, 27, 27001, 2, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "2030/12/17 14:59:59", 0.0, 27, 27002, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", "2030/12/17 14:59:59", 0.0, 27, 27003, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", "2030/12/17 14:59:59", 0.0, 27, 27004, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 1, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", "2030/12/17 14:59:59", 0.0, 28, 28001, 1, 190801, -363.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 2, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", "2030/12/17 14:59:59", 0.0, 28, 28002, 1, 190801, -363.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 3, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", "2030/12/17 14:59:59", 0.0, 29, 29001, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 4, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", "2030/12/17 14:59:59", 0.0, 29, 29002, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 5, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", "2030/12/17 14:59:59", 0.0, 30, 30001, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/09/24 15:00:00", 6, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", "2030/12/17 14:59:59", 0.0, 30, 30002, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/10/31 12:00:00", 7, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", "2030/12/17 14:59:59", 0.0, 31, 31001, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/10/31 12:00:00", 8, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", "2030/12/17 14:59:59", 0.0, 31, 31002, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 1, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", "2020/01/04 4:59:59", 0.0, 32, 32001, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 2, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "2020/01/04 4:59:59", 0.0, 32, 32002, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 3, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", "2020/01/04 4:59:59", 0.0, 33, 33001, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2019/12/20 5:00:00", 4, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "2020/01/04 4:59:59", 0.0, 33, 33002, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2020/01/04 5:00:00", 5, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", "2020/01/10 11:59:59", 0.0, 34, 34001, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2020/01/04 5:00:00", 6, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", "2020/01/10 11:59:59", 0.0, 34, 34002, 1, 190801, -409.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", "2030/12/17 14:59:59", 0.0, 38, 38001, 1, 105801, -458.0, 2, 5.3, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 2, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", "2030/12/17 14:59:59", 0.0, 38, 38002, 1, 105801, -458.0, 2, 6.5, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2020/04/01", 0, "", "2020/04/08 23:59:59", 9999.0, 39, 39005, 3, 105801, 9999.0, 3, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 2, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", "2030/12/17 14:59:59", 0.0, 40, 40001, 1, 190801, -430.0, 1, 0.0, 0, "カリン");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", "2030/12/17 14:59:59", 0.0, 41, 41001, 1, 106401, -363.0, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", "2030/12/17 14:59:59", 0.0, 41, 41002, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", "2030/12/17 14:59:59", 0.0, 41, 41003, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", "2030/12/17 14:59:59", 0.0, 41, 41004, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", "2030/12/17 14:59:59", 0.0, 42, 42001, 1, 105901, -416.5, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (2104010, "2015/12/17 15:00:00", 1, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", "2030/12/17 14:59:59", 0.0, 42, 42002, 1, 106401, -416.5, 1, 0.0, 0, "シェフィ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", "2030/12/17 14:59:59", 0.0, 42, 42003, 1, 105801, -416.5, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", "2030/12/17 14:59:59", 0.0, 42, 42004, 1, 106001, -416.5, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", "2030/12/17 14:59:59", 0.0, 43, 43001, 1, 105801, -363.0, 1, 0.0, 0, "ペコリーヌ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", "2030/12/17 14:59:59", 0.0, 43, 43002, 1, 105901, -363.0, 1, 0.0, 0, "コッコロ");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "2030/12/17 14:59:59", 0.0, 43, 43003, 1, 106001, -363.0, 1, 0.0, 0, "キャル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "2030/12/17 14:59:59", 0.0, 44, 43004, 1, 123001, -416.5, 1, 0.0, 0, "アメス");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 2, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", "2030/12/17 14:59:59", 0.0, 44, 43005, 1, 123001, -416.5, 1, 0.0, 0, "アメス");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 3, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "2030/12/17 14:59:59", 0.0, 45, 43006, 1, 123001, -416.5, 2, 5.79, 0, "アメス");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", "2030/12/17 14:59:59", 0.0, 46, 46001, 1, 123001, -371.5, 1, 0.0, 0, "アメス");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", "2030/12/17 14:59:59", 0.0, 47, 47001, 2, 104901, -416.5, 2, 0.0, 0, "シズル");
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (0, "2015/12/17 15:00:00", 1, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", "2030/12/17 14:59:59", 0.0, 47, 47002, 1, 101101, -416.5, 2, 9.32, 0, "リノ");
